import{_ as o,o as r,c as e,ai as a}from"./chunks/framework.DMjte4z8.js";const d=JSON.parse('{"title":"单位组完全指南：从概念到实战","description":"","frontmatter":{"title":"单位组完全指南：从概念到实战","category":"triggers","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.79,"discovered_via":"gap_finder","sources":["https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780","https://www.youtube.com/watch?v=LTElx6fQOK8","https://wc3we.fandom.com/wiki/GUI_Triggering","https://www.hiveworkshop.com/threads/better-triggers-custom-trigger-editor.341002/","https://github.com/stijnherfst/HiveWE"]},"headers":[],"relativePath":"triggers/单位组完全指南从概念到实战.md","filePath":"triggers/单位组完全指南从概念到实战.md","lastUpdated":1779353774000}'),l={name:"triggers/单位组完全指南从概念到实战.md"};function i(n,t,s,u,g,q){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="单位组完全指南-从概念到实战" tabindex="-1">单位组完全指南：从概念到实战 <a class="header-anchor" href="#单位组完全指南-从概念到实战" aria-label="Permalink to “单位组完全指南：从概念到实战”">​</a></h1><h2 id="什么是单位组-unit-group" tabindex="-1">什么是单位组（Unit Group）？ <a class="header-anchor" href="#什么是单位组-unit-group" aria-label="Permalink to “什么是单位组（Unit Group）？”">​</a></h2><p>本节将介绍<strong>单位组（Unit Group）</strong>这个概念。单位组是魔兽争霸3地图编辑器中用于<strong>同时管理多个单位</strong>的容器。学会单位组后，你就能对一个区域内的所有敌人、或者一群友军<strong>批量执行相同的操作</strong>，比如同时造成伤害、同时移动、同时播放特效——这将大大简化你的触发器（trigger）编写。</p><h3 id="单位组的定义与作用" tabindex="-1">单位组的定义与作用 <a class="header-anchor" href="#单位组的定义与作用" aria-label="Permalink to “单位组的定义与作用”">​</a></h3><p><strong>单位组</strong>你可以把它想象成一个<strong>&quot;篮子&quot;</strong>，你可以把任意多个单位&quot;放进去&quot;，然后一次性对篮子里的所有单位做操作。比如，你想让地图上某个区域内的所有敌方单位受到100点伤害，只需要：</p><ol><li>把这些单位放入一个单位组</li><li>对这个单位组执行&quot;对每个单位循环&quot;的操作</li><li>在循环内部，对每个单位造成100点伤害</li></ol><p>这样你不需要写10条、20条单独的伤害触发，而是用一条简洁的触发搞定所有单位。</p><blockquote><p><strong>💡 新手提示</strong>：单位组最强大的地方在于它是<strong>动态的</strong>——你可以随时向组里添加新单位，或者移除不需要的单位，而不需要事先规定&quot;这个组只能装5个单位&quot;。</p></blockquote><h3 id="单位组与单位数组的区别" tabindex="-1">单位组与单位数组的区别 <a class="header-anchor" href="#单位组与单位数组的区别" aria-label="Permalink to “单位组与单位数组的区别”">​</a></h3><p>很多新手会混淆<strong>单位组（Unit Group）</strong>和<strong>单位数组（Unit Array）</strong>，它们都能存储多个单位，但本质不同：</p><table tabindex="0"><thead><tr><th></th><th>单位组</th><th>单位数组</th></tr></thead><tbody><tr><td><strong>结构</strong></td><td>无序的&quot;单位集合&quot;</td><td>有编号的&quot;单位列表&quot;</td></tr><tr><td><strong>大小</strong></td><td>随时可变</td><td>需要预设固定大小</td></tr><tr><td><strong>查找</strong></td><td>无法直接按编号访问第N个单位</td><td>可以直接访问 <code>单位数组[3]</code></td></tr><tr><td><strong>适用场景</strong></td><td>对&quot;一群单位&quot;批量操作</td><td>按顺序/按编号处理单位</td></tr></tbody></table><p>简单来说：<strong>单位数组</strong>像是一排编好号的储物柜，你需要知道编号才能取出东西；<strong>单位组</strong>像是一个随用随取的篮子，你只需要知道&quot;我要对篮子里的所有东西做某件事&quot;。</p><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把单位组当成数组来用，试图用&quot;单位组[1]&quot;的方式访问第1个单位。这在单位组中<strong>无法直接实现</strong>——你需要用&quot;对每个单位执行动作&quot;循环来依次处理组内的单位。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><ul><li>单位组是一个<strong>存放多个单位的容器</strong>，适合批量操作</li><li>它与数组的区别在于：<strong>数组用编号管理，单位组用集合管理</strong></li><li>后续教程中，你将学习如何<strong>创建、添加、移除</strong>单位组中的单位，以及如何<strong>遍历</strong>组内的单位执行操作</li></ul><h2 id="创建单位组的基本方法" tabindex="-1">创建单位组的基本方法 <a class="header-anchor" href="#创建单位组的基本方法" aria-label="Permalink to “创建单位组的基本方法”">​</a></h2><p>本节将教你三种创建单位组的方法，从最简单的手动创建开始，到使用条件自动筛选。学完本节后，你将能够根据不同需求灵活选择最合适的建组方式。</p><h3 id="手动创建空单位组" tabindex="-1">手动创建空单位组 <a class="header-anchor" href="#手动创建空单位组" aria-label="Permalink to “手动创建空单位组”">​</a></h3><p>这是最基础的建组方法，适合需要手动往组里添加单位的场景。</p><ol><li><strong>打开触发器编辑器</strong> — 在顶部菜单栏点击&quot;触发器&quot;按钮（或按F4键）[^3]</li><li><strong>创建新变量</strong> — 右键点击左侧变量列表，选择&quot;新建变量&quot;</li><li><strong>设置变量类型</strong> — 将变量名改为你喜欢的名字（如&quot;我的单位组&quot;），类型下拉菜单中选择&quot;单位组&quot;[^3]</li><li><strong>初始化空组</strong> — 在触发器动作中添加&quot;设置变量&quot;动作，选择你刚创建的变量，等号右边选择&quot;单位组 - 空单位组&quot;</li></ol><blockquote><p><strong>💡 新手提示</strong>：单位组就像一个&quot;篮子&quot;，你创建的是一个空篮子，后续需要往里面放单位。如果不放任何单位就使用这个组，触发器可能会出错或什么都不会做。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记先初始化变量就直接使用，结果导致游戏报错。每次使用新的单位组变量前，一定要记得先用&quot;空单位组&quot;初始化它。</p></blockquote><h3 id="根据条件自动筛选单位" tabindex="-1">根据条件自动筛选单位 <a class="header-anchor" href="#根据条件自动筛选单位" aria-label="Permalink to “根据条件自动筛选单位”">​</a></h3><p>这种方法可以自动找出符合特定条件的单位，适合需要对一大群单位进行操作的场景。</p><ol><li><strong>创建条件筛选触发器</strong> — 新建一个触发器，添加&quot;单位组 - 选取区域内所有单位满足条件&quot;动作[^3]</li><li><strong>选择筛选区域</strong> — 点击&quot;区域&quot;输入框，在地图上拖动创建一个你要搜索的范围</li><li><strong>设置单位条件</strong> — 点击&quot;条件&quot;输入框，在弹出的条件编辑器中选择&quot;单位 - 单位的类型&quot;等条件</li><li><strong>保存结果到变量</strong> — 选取动作执行完毕后，符合条件的单位会自动放入你指定的单位组变量中</li></ol><blockquote><p><strong>💡 新手提示</strong>：条件筛选非常强大！比如你可以筛选&quot;所有血量低于30%的骑兵&quot;，然后对他们统一施放治疗法术。筛选条件可以叠加使用，满足多重条件。</p></blockquote><h3 id="使用预置条件快速建组" tabindex="-1">使用预置条件快速建组 <a class="header-anchor" href="#使用预置条件快速建组" aria-label="Permalink to “使用预置条件快速建组”">​</a></h3><p>为了提高效率，编辑器内置了许多常用的预置条件，让你不用每次都手动设置。</p><ol><li><strong>在选取动作中选择&quot;预置条件&quot;</strong> — 展开条件选择器，找到&quot;预置&quot;分类[^4]</li><li><strong>选择适合的预置</strong> — 常用预置包括： <ul><li>&quot;存活单位&quot; - 只选取没死的单位</li><li>&quot;同阵营单位&quot; - 只选取某一方的单位</li><li>&quot;可攻击的单位&quot; - 排除建筑、中立单位等</li></ul></li><li><strong>微调预置条件</strong> — 某些预置允许你进一步调整参数，比如选择具体是哪个玩家阵营</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易混淆&quot;单位类型&quot;和&quot;单位标签&quot;。单位类型是指&quot;骑士&quot;、&quot;法师&quot;这类分类，而标签是一种自定义标记。别选错了！</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三种方法的学习后，你应该能够：</p><ul><li>✅ 创建空单位组并手动添加单位</li><li>✅ 使用条件自动筛选符合条件的单位</li><li>✅ 利用预置条件快速建组</li></ul><p>在实际制作中，<strong>推荐优先使用预置条件</strong>，因为它既快速又不容易出错。只有当预置条件无法满足需求时，才需要手动设置更复杂的自定义条件。</p><h2 id="单位组的核心操作" tabindex="-1">单位组的核心操作 <a class="header-anchor" href="#单位组的核心操作" aria-label="Permalink to “单位组的核心操作”">​</a></h2><p>本节我们将学习对单位组进行增删改查的基本操作。学完后，你能够灵活地往单位组里添加或移除单位，逐个检查组内的单位，并正确地清空不需要的单位组。</p><h3 id="遍历单位组中的每个单位" tabindex="-1">遍历单位组中的每个单位 <a class="header-anchor" href="#遍历单位组中的每个单位" aria-label="Permalink to “遍历单位组中的每个单位”">​</a></h3><ol><li><strong>第一步：创建单位组变量</strong> — 在触发器编辑器的变量列表中，点击&quot;新建变量&quot;（绿色加号按钮），变量类型选择&quot;单位组&quot;，给变量起个名字比如<code>临时单位组</code>[^1]</li><li><strong>第二步：使用&quot;选取区域内单位&quot;动作</strong> — 在触发器动作中找到&quot;选取区域内单位&quot;（Units in region），这个动作会自动把某个区域内的所有单位放入你的单位组变量中[^3]</li><li><strong>第三步：遍历单位</strong> — 展开&quot;选取区域内单位&quot;动作的子选项，选择&quot;执行动作&quot;，然后添加一个循环。常用的组合是：<code>For each (Integer A) from 1 to (Number of units in 单位组)，执行动作</code>[^3]</li><li><strong>第四步：对每个单位操作</strong> — 在循环内部，你可以使用<code>Set VariableSet tempUnit = (Picked unit)</code>获取当前正在处理的单位，然后对这个单位进行你想要的操作</li></ol><blockquote><p><strong>💡 新手提示</strong>：选择&quot;选取区域内单位&quot;时，记得先在地图编辑器中创建一个<strong>区域（Region）</strong>，没有区域就没办法告诉电脑去哪个范围找单位。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易忘记&quot;选取区域内单位&quot;是一个<strong>动作（Action）</strong>，必须放在触发器的<strong>执行（Actions）</strong>部分，而不是条件（Conditions）部分。</p></blockquote><h3 id="添加与移除单位" tabindex="-1">添加与移除单位 <a class="header-anchor" href="#添加与移除单位" aria-label="Permalink to “添加与移除单位”">​</a></h3><ol><li><strong>第一步：添加单个单位到组</strong> — 在动作列表中找到&quot;Add unit to unit group&quot;，将你想要加入的单位（可以是某个具体单位，也可以是触发事件中的&quot;触发单位&quot;或&quot;生效单位&quot;）添加进去[^3]</li><li><strong>第二步：使用&quot;选取&quot;动作批量添加</strong> — 如果你需要添加多个单位，比如所有某种类型的单位，使用&quot;选取单位&quot;动作配合&quot;添加到单位组&quot;条件来批量操作</li><li><strong>第三步：从单位组移除单位</strong> — 找到&quot;Remove unit from unit group&quot;动作，选择要移除的单位和你要操作的单位组</li><li><strong>第四步：特别注意</strong> — 移除单位并不会消灭这个单位本身，它只是从组里消失而已。如果你想同时删除单位，需要额外使用&quot;Kill unit&quot;或&quot;Remove unit&quot;动作[^3]</li></ol><blockquote><p><strong>💡 新手提示</strong>：如果单位被移出单位组后你还想继续使用它，一定要先用一个<strong>单位变量</strong>保存它，否则之后就没办法再找到它了。</p></blockquote><h3 id="清空与销毁单位组" tabindex="-1">清空与销毁单位组 <a class="header-anchor" href="#清空与销毁单位组" aria-label="Permalink to “清空与销毁单位组”">​</a></h3><ol><li><strong>第一步：清空单位组</strong> — 找到&quot;Clear unit group&quot;动作，选择你要清空的单位组。这个动作会把组里<strong>所有单位都移除</strong>，但不会删除那些单位本身[^3]</li><li><strong>第二步：销毁单位组（高级）</strong> — 如果你使用的是<strong>JASS或Lua脚本</strong>，可以用<code>DestroyGroup()</code>函数完全销毁单位组释放内存。但在GUI界面中，频繁清空再重新填充通常就够了</li><li><strong>第三步：判断单位组是否为空</strong> — 使用&quot;Number of units in unit group&quot;函数检查，如果返回值是0，说明组已经被清空了</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手混淆了&quot;清空单位组&quot;和&quot;删除单位&quot;。清空只是把单位从组里拿出来，单位还在地图上；删除单位（Kill/Remove）才是真正让单位从游戏中消失。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个部分的学习后，你应该掌握了：</p><ul><li>如何使用&quot;选取区域内单位&quot;并配合循环遍历组内每个单位进行操作</li><li>如何通过&quot;添加/移除单位到单位组&quot;来动态管理组内成员</li><li>如何使用&quot;清空单位组&quot;正确地重置一个不再需要的单位组</li></ul><p><strong>实战练习</strong>：试着创建一个触发器，让你在地图中央区域放置5个步兵，然后写一个触发器把这些步兵全部选出来并对每个步兵播放一段文字提示。这样你就完成了一次完整的&quot;添加→选取→操作&quot;的循环练习！</p><h2 id="单位组的实战应用场景" tabindex="-1">单位组的实战应用场景 <a class="header-anchor" href="#单位组的实战应用场景" aria-label="Permalink to “单位组的实战应用场景”">​</a></h2><p>在了解了单位组的基本概念后，这一节我们将学习<strong>如何在实际地图中运用单位组</strong>。学完本节后，你将能够实现&quot;对一片区域内的所有敌人释放技能&quot;、&quot;自动识别战场上的敌我单位&quot;等常见功能。</p><h3 id="群体技能释放" tabindex="-1">群体技能释放 <a class="header-anchor" href="#群体技能释放" aria-label="Permalink to “群体技能释放”">​</a></h3><p>群体技能是RPG地图中最常用的功能之一，比如&quot;对半径300范围内的所有敌人造成伤害&quot;。这需要先收集区域内的单位，再对每个单位执行动作。</p><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>创建触发器</strong> — 在触发器编辑器中新建一个触发器，命名为&quot;群体AOE技能&quot;[^1]</li><li><strong>设置触发条件</strong> — 添加&quot;单位使用技能&quot;事件，选择你想要触发的技能ID[^2]</li><li><strong>创建单位组变量</strong> — 在变量编辑器中新建&quot;单位组&quot;类型的变量，命名为<code>aoe_targets</code>[^3]</li><li><strong>收集目标单位</strong> — 使用&quot;单位组 - 选取范围内所有单位&quot;动作，以技能施放点为中心，半径设为300，存入<code>aoe_targets</code>变量[^1]</li><li><strong>循环遍历单位</strong> — 添加&quot;单位组 - 选取每个单位&quot;动作，对<code>aoe_targets</code>中的每个单位施加伤害或附加效果[^3]</li><li><strong>清理内存</strong> — 动作执行完毕后，使用&quot;单位组 - 移除单位&quot;销毁临时单位组，避免内存泄漏[^4]</li></ol><blockquote><p><strong>💡 新手提示</strong>：群体技能的范围最好设置为可调节的变量，这样你可以轻松修改技能的覆盖半径，而不用改代码。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记第6步清理单位组。临时创建的单位组如果不销毁，会导致地图运行越来越卡，甚至崩溃。</p></blockquote><h3 id="区域判定与敌我识别" tabindex="-1">区域判定与敌我识别 <a class="header-anchor" href="#区域判定与敌我识别" aria-label="Permalink to “区域判定与敌我识别”">​</a></h3><p>在防守类或塔防类地图中，你可能需要检测某片区域是否被敌人入侵，或者统计当前有多少友军和敌军。</p><h4 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>定义区域</strong> — 在地图编辑器中，用&quot;区域工具&quot;在需要监测的位置画一个矩形区域[^5]</li><li><strong>创建单位组</strong> — 新建两个单位组变量：<code>enemies_in_zone</code>（区域内的敌人）和<code>allies_in_zone</code>（区域内的友军）</li><li><strong>获取区域内的单位</strong> — 使用&quot;单位组 - 选取区域内的单位&quot;动作，把所有单位放入一个临时组[^1]</li><li><strong>过滤敌我</strong> — 使用&quot;条件 - 单位属于玩家&quot;或&quot;单位 - 获取单位所有者&quot;来区分敌我[^3]</li><li><strong>执行对应逻辑</strong> — 如果敌人数量大于0，则触发防御机制；如果是友军，则可以触发增益效果</li></ol><blockquote><p><strong>💡 新手提示</strong>：敌我识别时，记得考虑&quot;中立敌对&quot;单位（如野怪），它们的所有者通常是玩家24（系统）。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易混淆&quot;玩家1的友军&quot;和&quot;玩家1的单位&quot;。前者包括玩家1及其盟友的所有单位，后者只包括玩家1自己的单位。</p></blockquote><h3 id="编队管理与批量操作" tabindex="-1">编队管理与批量操作 <a class="header-anchor" href="#编队管理与批量操作" aria-label="Permalink to “编队管理与批量操作”">​</a></h3><p>在rpg地图中，玩家经常需要控制多个单位进行战斗。单位组可以帮助你实现&quot;一键选中所有前锋部队&quot;或&quot;让所有治疗单位治疗血量最低的队友&quot;。</p><h4 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>建立编队单位组</strong> — 在触发器中预设一个包含编队成员的单位组，例如<code>tank_group</code>包含所有坦克[^1]</li><li><strong>响应快捷键</strong> — 使用&quot;玩家 - 玩家1按下了哪个键&quot;作为触发条件[^3]</li><li><strong>批量选中单位</strong> — 使用&quot;选择 - 选择/取消选择&quot;动作，对<code>tank_group</code>中的所有单位执行选中[^2]</li><li><strong>批量下达命令</strong> — 使用&quot;单位 - 命令单位移动/攻击&quot;动作，让所有编队单位同时执行指令[^1]</li></ol><blockquote><p><strong>💡 新手提示</strong>：批量操作时，可以使用&quot;单位组 - 随机选择单位&quot;来让不同单位攻击不同的目标，避免所有单位挤在一起攻击同一个敌人。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：不要在每个帧（游戏循环）内频繁创建和销毁单位组，这会严重影响性能。尽量复用已有的单位组变量。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>通过本节学习，你已经掌握了单位组的三大实战应用：<strong>群体技能</strong>、<strong>敌我识别</strong>和<strong>编队管理</strong>。这三种场景覆盖了绝大多数RPG地图的核心需求。建议你先从&quot;群体技能释放&quot;开始练习，因为它最能帮助你理解单位组的&quot;收集→处理→清理&quot;完整流程。</p><h2 id="常见问题与性能优化" tabindex="-1">常见问题与性能优化 <a class="header-anchor" href="#常见问题与性能优化" aria-label="Permalink to “常见问题与性能优化”">​</a></h2><p>本节将帮助你解决使用单位组时最常遇到的&quot;内存泄漏&quot;问题，以及如何在不同场景下选择正确的清空或销毁方式。学完本节后，你的地图将能更稳定运行，即使单位数量很多也不会卡顿。</p><h3 id="单位组泄漏问题解析" tabindex="-1">单位组泄漏问题解析 <a class="header-anchor" href="#单位组泄漏问题解析" aria-label="Permalink to “单位组泄漏问题解析”">​</a></h3><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手发现地图运行几分钟后开始变卡，甚至崩溃，这通常是<strong>单位组泄漏</strong>造成的。</p></blockquote><p><strong>单位组泄漏</strong>是什么？简单说就是：当你创建一个单位组后忘记清理它，这部分&quot;记忆&quot;就会一直占用电脑资源，久而久之电脑就变慢了。</p><h4 id="操作步骤-3" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-3" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>理解泄漏的原因</strong> — 当你使用&quot;设置变量&quot;动作创建一个单位组后，如果不再使用这个变量，WE（World Editor）不会自动清理它[^1]</li><li><strong>检查你的触发器</strong> — 在触发器编辑器中，找到所有使用&quot;单位组&quot;的动作，特别是&quot;添加单位到单位组&quot;和&quot;设置单位组变量&quot;的地方</li><li><strong>在触发器末尾添加清空动作</strong> — 每个可能重复执行的触发器，都应该在最后加上&quot;清空单位组&quot;动作，确保每次运行后清理干净[^3]</li></ol><blockquote><p><strong>💡 新手提示</strong>：养成习惯——只要触发器里创建了单位组，就一定要在触发器末尾清空它，就像吃完饭要洗碗一样。</p></blockquote><h3 id="何时清空-vs-何时销毁" tabindex="-1">何时清空 vs 何时销毁 <a class="header-anchor" href="#何时清空-vs-何时销毁" aria-label="Permalink to “何时清空 vs 何时销毁”">​</a></h3><p>这是两个不同的动作，很多新手搞不清楚。</p><table tabindex="0"><thead><tr><th>情况</th><th>应该使用</th><th>原因</th></tr></thead><tbody><tr><td>单位组变量还需要用</td><td><strong>清空</strong></td><td>只清除内容，变量还在</td></tr><tr><td>完全不再需要这个变量</td><td><strong>销毁</strong></td><td>完全删除，释放内存</td></tr></tbody></table><h4 id="操作步骤-4" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-4" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>打开触发器编辑器</strong> — 双击任意触发器，进入编辑界面</li><li><strong>找到单位组动作</strong> — 在动作列表中，搜索&quot;清空&quot;或&quot;销毁&quot;[^3]</li><li><strong>清空单位组</strong> — 选择&quot;清空单位组&quot;动作，选择对应的变量名。这会移除组内所有单位，但变量本身保留</li><li><strong>销毁单位组</strong> — 选择&quot;销毁单位组&quot;动作。这会完全删除这个单位组，通常用于不再需要的临时组</li></ol><blockquote><p><strong>💡 新手提示</strong>：一般建议<strong>优先使用&quot;清空&quot;</strong>，除非你确定这个变量真的不会再用了。</p></blockquote><h3 id="优化大型单位组的技巧" tabindex="-1">优化大型单位组的技巧 <a class="header-anchor" href="#优化大型单位组的技巧" aria-label="Permalink to “优化大型单位组的技巧”">​</a></h3><p>如果你的地图有大量单位（比如怪物群、召唤物），单位组操作会变慢。</p><h4 id="操作步骤-5" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-5" aria-label="Permalink to “操作步骤”">​</a></h4><ol><li><strong>减少不必要的单位组创建</strong> — 不要在&quot;每个X秒&quot;这种循环触发器里频繁创建新单位组，尽量复用已有的变量</li><li><strong>使用&quot;选取区域内单位&quot;时要限定条件</strong> — 比如只选&quot;存活单位&quot;或&quot;属于某玩家&quot;，避免选取太多无用单位[^2]</li><li><strong>及时清理死亡的单位</strong> — 使用&quot;单位死亡&quot;事件触发器，在单位死亡时立即将其从相关单位组中移除</li><li><strong>避免在循环中反复添加/移除单位</strong> — 如果必须在循环中操作单位组，先把单位存到一个临时列表或变量里，循环结束后再统一处理</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手喜欢在&quot;每0.01秒&quot;的快循环里频繁清空和重建单位组，这会导致严重卡顿。解决方法是把循环间隔改为至少0.5秒。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上学习后，你应该：</p><ul><li>✅ 能够识别并修复单位组泄漏问题</li><li>✅ 知道何时使用&quot;清空&quot;、何时使用&quot;销毁&quot;</li><li>✅ 掌握优化大型单位组的基本技巧</li></ul><blockquote><p><strong>💡 新手提示</strong>：写完触发器后，多测试几遍，观察地图运行时间变长没有。如果变卡了，很可能是某个触发器里有泄漏问题。</p></blockquote><h2 id="进阶技巧与常见错误" tabindex="-1">进阶技巧与常见错误 <a class="header-anchor" href="#进阶技巧与常见错误" aria-label="Permalink to “进阶技巧与常见错误”">​</a></h2><p>本节将教你如何正确使用嵌套单位组，并帮助你避免新手最常犯的错误。学完本节后，你将能够更高效地管理大量单位，并编写不会导致游戏卡顿的触发器。</p><h3 id="嵌套单位组的正确用法" tabindex="-1">嵌套单位组的正确用法 <a class="header-anchor" href="#嵌套单位组的正确用法" aria-label="Permalink to “嵌套单位组的正确用法”">​</a></h3><p>在复杂地图中，你可能需要将单位按不同类型分组后再统一操作。这时嵌套使用单位组就很有用了。</p><ol><li><p><strong>创建主单位组</strong> — 在触发器中新建一个&quot;单位组&quot;类型的变量（比如叫&quot;所有近战单位&quot;），用&quot;获取范围内单位&quot;动作填充它[^1]</p></li><li><p><strong>在循环中筛选子组</strong> — 使用&quot;遍历单位组中每个单位&quot;动作（Pick Every Unit），在循环内部根据条件再创建新的临时单位组[^3]</p></li><li><p><strong>记得清理临时组</strong> — 每次使用完临时单位组后，务必用&quot;清除单位组&quot;动作释放内存，否则长期运行会拖累游戏性能</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：想象单位组就像一个&quot;容器&quot;，嵌套使用就是在容器里再放小容器。操作时记得&quot;用完要倒掉&quot;！</p></blockquote><h3 id="新手常犯的错误与避免方法" tabindex="-1">新手常犯的错误与避免方法 <a class="header-anchor" href="#新手常犯的错误与避免方法" aria-label="Permalink to “新手常犯的错误与避免方法”">​</a></h3><blockquote><p><strong>⚠️ 常见错误 1</strong>：把单个单位和单位组搞混</p><ul><li>很多新手会对一个单位使用&quot;遍历单位组&quot;动作，这会报错</li><li>解决方法：单个单位用&quot;单位&quot;类型变量，单位组才用&quot;单位组&quot;类型变量[^3]</li></ul></blockquote><blockquote><p><strong>⚠️ 常见错误 2</strong>：忘记清除单位组导致游戏变卡</p><ul><li>每次用&quot;获取范围内单位&quot;创建的单位组，如果不手动清除，内存会一直被占用</li><li>解决方法：在触发器结尾添加&quot;清除单位组&quot;动作，养成好习惯[^4]</li></ul></blockquote><blockquote><p><strong>⚠️ 常见错误 3</strong>：在循环中重复创建相同的单位组</p><ul><li>有些新手会在每次循环时都新建单位组，导致效率极低</li><li>解决方法：循环外创建一次，循环内反复使用同一个变量</li></ul></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能：</p><ul><li>✅ 正确创建和使用嵌套单位组</li><li>✅ 避免单位组相关的报错</li><li>✅ 编写出不会造成内存泄漏的触发器</li></ul><p>记住：<strong>单位组是工具，用完要清理，嵌套要谨慎，变量要对齐。</strong></p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://world-editor-tutorials.thehelper.net/cat_usersubmit.php?view=19780" target="_blank" rel="noreferrer">Triggers - Basic Guide</a> — accessed 2026-05-21 [^2]: <a href="https://www.youtube.com/watch?v=LTElx6fQOK8" target="_blank" rel="noreferrer">How to Use Trigger Editor to Create a Spell on Warcraft 3 World...</a> — accessed 2026-05-21 [^3]: <a href="https://wc3we.fandom.com/wiki/GUI_Triggering" target="_blank" rel="noreferrer">GUI Triggering | Warcraft 3 World Editor Wiki | Fandom</a> — accessed 2026-05-21 [^4]: <a href="https://www.hiveworkshop.com/threads/better-triggers-custom-trigger-editor.341002/" target="_blank" rel="noreferrer">Better Triggers (Custom Trigger Editor) | HIVE</a> — accessed 2026-05-21 [^5]: <a href="https://github.com/stijnherfst/HiveWE" target="_blank" rel="noreferrer">GitHub - stijnherfst/HiveWE: A Warcraft III world editor. · GitHub</a> — accessed 2026-05-21</p>',111)])])}const c=o(l,[["render",i]]);export{d as __pageData,c as default};
